from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import sqlite3
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from datetime import datetime, timedelta
import time
from collections import defaultdict

app = Flask(__name__)

# In-memory rate limiting (use Redis in production)
rate_limits = defaultdict(list)
MAX_REQUESTS = 5
TIME_WINDOW = 300  # 5 minutes

def get_db():
    conn = sqlite3.connect('users.db')
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    conn = get_db()
    conn.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL
        )
    ''')
    conn.execute('''
        CREATE TABLE IF NOT EXISTS password_resets (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT NOT NULL,
            token TEXT UNIQUE NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            expires_at TIMESTAMP NOT NULL
        )
    ''')
    conn.commit()
    conn.close()

def send_reset_email(email, reset_link):
    # Simulate email sending
    print(f"Sending reset link to {email}: {reset_link}")

def is_rate_limited(ip_address):
    now = time.time()
    requests = rate_limits[ip_address]
    # Remove old requests outside time window
    requests[:] = [req_time for req_time in requests if now - req_time < TIME_WINDOW]
    
    if len(requests) >= MAX_REQUESTS:
        return True
    
    requests.append(now)
    return False

@app.route('/reset-password', methods=['POST'])
def request_password_reset():
    ip_address = request.environ.get('HTTP_X_FORWARDED_FOR', request.remote_addr)
    
    if is_rate_limited(ip_address):
        return jsonify({'error': 'Too many requests. Please try again later.'}), 429
    
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email is required'}), 400
    
    try:
        conn = get_db()
        user = conn.execute('SELECT * FROM users WHERE email = ?', (email,)).fetchone()
        
        if not user:
            # Still return success to prevent email enumeration
            return jsonify({'message': 'If an account exists with that email, a reset link has been sent.'}), 200
        
        # Generate token
        token = secrets.token_urlsafe(32)
        expires_at = datetime.now() + timedelta(hours=1)
        
        # Store reset token
        conn.execute('''
            INSERT INTO password_resets (email, token, expires_at)
            VALUES (?, ?, ?)
        ''', (email, token, expires_at))
        conn.commit()
        
        # Send reset link (in production, use actual email service)
        reset_link = f"http://localhost:5000/reset?token={token}"
        send_reset_email(email, reset_link)
        
        return jsonify({'message': 'If an account exists with that email, a reset link has been sent.'}), 200
        
    except Exception as e:
        return jsonify({'error': 'An error occurred. Please try again.'}), 500
    finally:
        conn.close()

@app.route('/reset', methods=['POST'])
def reset_password():
    data = request.get_json()
    token = data.get('token')
    new_password = data.get('password')
    
    if not token or not new_password:
        return jsonify({'error': 'Token and password are required'}), 400
    
    try:
        conn = get_db()
        reset_record = conn.execute('''
            SELECT * FROM password_resets 
            WHERE token = ? AND expires_at > ?
        ''', (token, datetime.now())).fetchone()
        
        if not reset_record:
            return jsonify({'error': 'Invalid or expired reset token'}), 400
        
        # Update user password
        user = conn.execute('SELECT * FROM users WHERE email = ?', (reset_record['email'],)).fetchone()
        if user:
            password_hash = generate_password_hash(new_password)
            conn.execute('UPDATE users SET password_hash = ? WHERE email = ?', (password_hash, reset_record['email']))
            conn.execute('DELETE FROM password_resets WHERE token = ?', (token,))
            conn.commit()
            
            return jsonify({'message': 'Password reset successfully'}), 200
        
        return jsonify({'error': 'User not found'}), 404
        
    except Exception as e:
        return jsonify({'error': 'An error occurred. Please try again.'}), 500
    finally:
        conn.close()

if __name__ == '__main__':
    init_db()
    app.run(debug=False)